// Usage Example
// ============================================================

// Initialize the OAuth client
const oauthClient = new OAuthImplicitClient({
  clientId: 'your-client-id',
  authorizationEndpoint: 'https://auth.example.com/oauth/authorize',
  redirectUri: window.location.origin + '/callback',
  scope: 'read write profile',
  apiBaseUrl: 'https://api.example.com/v1'
});

// Register event handlers
oauthClient
  .on('tokenReceived', (tokenInfo) => {
    console.log('Token received successfully!');
    console.log('Token type:', tokenInfo.tokenType);
    console.log('Expires in:', tokenInfo.expiresIn, 'seconds');
    // Update UI to show logged-in state
    initializeApp();
  })
  .on('tokenExpired', () => {
    console.log('Token has expired. Redirecting to login...');
    // Show login prompt or auto-redirect
    showLoginPrompt();
  })
  .on('error', (error) => {
    console.error('OAuth error:', error.code, error.message);
    showErrorMessage(error.message);
  });

// Example: Login button handler
function handleLogin() {
  oauthClient.authorize();
}

// Example: Logout button handler
function handleLogout() {
  oauthClient.logout();
  updateUIForLoggedOut();
}

// Example: Making API calls
async function initializeApp() {
  if (!oauthClient.isAuthenticated()) {
    showLoginPrompt();
    return;
  }

  try {
    // GET request
    const userProfile = await oauthClient.getJSON('/user/profile');
    console.log('User profile:', userProfile);

    // POST request
    const newItem = await oauthClient.postJSON('/items', {
      name: 'New Item',
      description: 'Created via API'
    });
    console.log('Created item:', newItem);

    // Custom request with additional options
    const response = await oauthClient.apiCall('/data/export', {
      method: 'GET',
      headers: { Accept: 'text/csv' }
    });
    const csvData = await response.text();
    console.log('CSV data:', csvData);
  } catch (error) {
    if (error instanceof OAuthError && error.code === 'token_invalid') {
      // Re-authenticate
      oauthClient.authorize();
    } else {
      console.error('API Error:', error);
    }
  }
}

// Example: Display token info
function displayTokenInfo() {
  const tokenData = oauthClient.getTokenData();
  if (tokenData) {
    console.log('Access Token:', tokenData.accessToken.substring(0, 10) + '...');
    console.log('Token Type:', tokenData.tokenType);
    console.log('Stored At:', tokenData.storedAt);
    console.log('Expires At:', tokenData.expiresAt);
    console.log('Remaining:', tokenData.remainingSeconds, 'seconds');
  }
}

// Placeholder UI functions for the example
function showLoginPrompt() {
  console.log('Please log in to continue.');
}

function showErrorMessage(message) {
  console.error('Error:', message);
}

function updateUIForLoggedOut() {
  console.log('User logged out.');
}

// Auto-initialize on page load
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', () => {
    if (oauthClient.isAuthenticated()) {
      initializeApp();
    } else {
      showLoginPrompt();
    }
  });
} else {
  if (oauthClient.isAuthenticated()) {
    initializeApp();
  } else {
    showLoginPrompt();
  }
}